import React, { useState, useEffect } from "react";
import "./NewsList.css";

const NewsList = () => {
  const [news, setNews] = useState([]);
  const [search, setSearch] = useState("");

  useEffect(() => {
    fetch("http://localhost:5000/news")
      .then(res => res.json())
      .then(data => {
        if (Array.isArray(data)) setNews(data);
        else setNews([]);
      })
      .catch(err => console.error("Fetch error:", err));
  }, []);

  const filteredNews = Array.isArray(news)
  ? news
      .filter(n => n.title?.toLowerCase().includes(search.toLowerCase()))
      .sort((a, b) => new Date(b.date) - new Date(a.date)) // Сортировка по убыванию даты
  : [];

  return (
    <div className="news-container">
      <h2>Новини</h2>

      <div className="filter-form">
        <input
          type="text"
          placeholder="Пошук новини..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
        <button onClick={() => setSearch("")}>Очистити</button>
      </div>

      <div className="news-grid">
        {filteredNews.length > 0 ? (
          filteredNews.map(item => (
            <div key={item.id} className="news-card">
              <h3>{item.title}</h3>
              <p>{item.content}</p>
              <span>📅 {new Date(item.date).toLocaleString()}</span>
            </div>
          ))
        ) : (
          <p className="no-results">Новин не знайдено :(</p>
        )}
      </div>
    </div>
  );
};

export default NewsList;
